1	type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	type QuoteStep = { op: "quote"; items: Item[] };
8	type Damage = { itemType: string; amount: number };
9	type Incident = { cause?: string; damages: Damage[] };
10	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
11	type Step = QuoteStep | ClaimStep;
12	type Customer = { yearsWithMHPCO: number };
13	type Scenario = { customer: Customer; steps: Step[] };
14	type QuoteResult = { premium: number };
15	type ClaimResult = { payout: number; remainingCap: number };
16	type StepResult = QuoteResult | ClaimResult;
17	
18	const PROCESSING_FEE = 5;
19	const FIRST_INSURANCE_RATE = 0.1;
20	const CURSE_RATE = 0.5;
21	const HIGH_ENCHANTMENT_RATE = 0.3;
22	const HIGH_ENCHANTMENT_THRESHOLD = 5;
23	const LOYALTY_RATE = 0.2;
24	const LOYALTY_THRESHOLD = 2;
25	const FOLLOWUP_RATE = 0.15;
26	const COMPONENT_BASE_PREMIUM = 25;
27	const COMPONENT_INSURANCE_VALUE = 250;
28	const BLOCK_SIZE = 3;
29	const BLOCK_BASE_PREMIUM = 60;
30	const DEDUCTIBLE = 100;
31	const CAP_MULTIPLIER = 2;
32	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
33	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
34	
35	const BASE_PREMIUMS: Record<string, number> = {
36	  sword: 100,
37	  amulet: 60,
38	  staff: 80,
39	  potion: 40,
40	};
41	
42	const INSURANCE_VALUES: Record<string, number> = {
43	  sword: 1000,
44	  amulet: 600,
45	  staff: 800,
46	  potion: 400,
47	};
48	
49	const KNOWN_COMPONENT_TYPES = new Set(["rune", "moonstone"]);
50	
51	const isKnownItemType = (type: string): boolean =>
52	  BASE_PREMIUMS[type] !== undefined || KNOWN_COMPONENT_TYPES.has(type);
53	
54	const isComponent = (item: Item): boolean => BASE_PREMIUMS[item.type] === undefined;
55	
56	const componentGroupBase = (count: number): number =>
57	  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * COMPONENT_BASE_PREMIUM;
58	
59	const countByType = (items: Item[]): Map<string, number> =>
60	  items.reduce(
61	    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
62	    new Map<string, number>(),
63	  );
64	
65	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type];
66	const itemInsuranceValue = (item: Item): number =>
67	  isComponent(item) ? COMPONENT_INSURANCE_VALUE : INSURANCE_VALUES[item.type];
68	
69	const componentsBaseTotal = (components: Item[]): number =>
70	  [...countByType(components).values()].reduce(
71	    (sum, count) => sum + componentGroupBase(count),
72	    0,
73	  );
74	
75	const partitionByComponent = (items: Item[]): { mainItems: Item[]; components: Item[] } =>
76	  items.reduce<{ mainItems: Item[]; components: Item[] }>(
77	    (acc, item) => {
78	      (isComponent(item) ? acc.components : acc.mainItems).push(item);
79	      return acc;
80	    },
81	    { mainItems: [], components: [] },
82	  );
83	
84	const mainItemsBaseTotal = (items: Item[]): number =>
85	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
86	
87	const policyBase = (items: Item[]): number => {
88	  const { mainItems, components } = partitionByComponent(items);
89	  return mainItemsBaseTotal(mainItems) + componentsBaseTotal(components);
90	};
91	
92	const insuranceSum = (items: Item[]): number =>
93	  items.reduce((sum, item) => sum + itemInsuranceValue(item), 0);
94	
95	const isCursed = (item: Item): boolean => item.cursed === true;
96	const isHighlyEnchanted = (item: Item): boolean =>
97	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
98	
99	const itemSurcharge = (item: Item): number => {
100	  if (isComponent(item)) return 0;
101	  const base = itemBasePremium(item);
102	  const rate = (isCursed(item) ? CURSE_RATE : 0) + (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_RATE : 0);
103	  return base * rate;
104	};
105	
106	const itemSurchargesTotal = (items: Item[]): number =>
107	  items.reduce((sum, item) => sum + itemSurcharge(item), 0);
108	
109	const isLoyal = (customer: Customer): boolean => customer.yearsWithMHPCO >= LOYALTY_THRESHOLD;
110	
111	const loyaltyDiscount = (base: number, customer: Customer): number =>
112	  isLoyal(customer) ? base * LOYALTY_RATE : 0;
113	
114	type Policy = {
115	  items: Item[];
116	  remainingCap: number;
117	};
118	
119	const computeQuote = (step: QuoteStep, customer: Customer, quoteIndex: number): QuoteResult => {
120	  for (const item of step.items) {
121	    if (!isKnownItemType(item.type)) {
122	      throw new Error(`Unknown item type: ${item.type}`);
123	    }
124	  }
125	  const base = policyBase(step.items);
126	  const surcharges = itemSurchargesTotal(step.items);
127	  const firstInsurance = base * FIRST_INSURANCE_RATE;
128	  const loyalty = loyaltyDiscount(base, customer);
129	  const followup = quoteIndex > 0 ? base * FOLLOWUP_RATE : 0;
130	  const premium = Math.ceil(base + surcharges + firstInsurance - loyalty - followup) + PROCESSING_FEE;
131	  return { premium };
132	};
133	
134	const hasHighEnchantmentPayout = (item: Item): boolean =>
135	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD;
136	
137	const reimbursableAmount = (damage: Damage, item: Item): number =>
138	  hasHighEnchantmentPayout(item) ? damage.amount * HIGH_ENCHANTMENT_PAYOUT_RATE : damage.amount;
139	
140	const computeDamagePayout = (damage: Damage, item: Item): number =>
141	  Math.max(0, reimbursableAmount(damage, item) - DEDUCTIBLE);
142	
143	const findPolicyItem = (policy: Policy, itemType: string): Item =>
144	  policy.items.find((item) => item.type === itemType)!;
145	
146	const computeClaim = (step: ClaimStep, policies: Map<number, Policy>): ClaimResult => {
147	  const policy = policies.get(step.policy)!;
148	  const grossPayout = step.incident.damages.reduce(
149	    (sum, damage) => sum + computeDamagePayout(damage, findPolicyItem(policy, damage.itemType)),
150	    0,
151	  );
152	  const payout = Math.min(grossPayout, policy.remainingCap);
153	  policy.remainingCap -= payout;
154	  return { payout, remainingCap: policy.remainingCap };
155	};
156	
157	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
158	  const policies = new Map<number, Policy>();
159	  let quoteIndex = 0;
160	  const results = scenario.steps.map((step, stepIndex) => {
161	    if (step.op === "quote") {
162	      const result = computeQuote(step, scenario.customer, quoteIndex);
163	      policies.set(stepIndex, {
164	        items: step.items,
165	        remainingCap: insuranceSum(step.items) * CAP_MULTIPLIER,
166	      });
167	      quoteIndex += 1;
168	      return result;
169	    }
170	    return computeClaim(step, policies);
171	  });
172	  return { results };
173	};
